/**
 * Web Search Extension
 *
 * Provides web search capability using free, no-API-key-required sources:
 *   1. DuckDuckGo HTML — general web search
 *   2. Wikipedia API — focused article search
 *
 * Installation:
 *   This file is already in ~/.pi/agent/extensions/ (auto-loaded).
 *   On first use after pi starts, run:  pi -e ./web-search.ts  (or just /reload)
 *
 * Usage:
 *   Call the web_search tool with a query string to research any topic.
 *   Call the wikipedia_search tool for specific Wikipedia article lookups.
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import type { Static } from "@sinclair/typebox";
import { Type } from "@sinclair/typebox";

// ─── Tool schemas ───────────────────────────────────────────────────────────

const webSearchParams = Type.Object({
  query: Type.String({
    description: "Search query (e.g. 'latest React hooks patterns')",
    minLength: 1,
  }),
  max_results: Type.Optional(
    Type.Number({
      description: "Maximum number of results to return (default: 5, max: 12)",
      minimum: 1,
      maximum: 12,
    }),
  ),
});

const wikiSearchParams = Type.Object({
  query: Type.String({
    description: "Search query (e.g. 'TypeScript generics')",
    minLength: 1,
  }),
  max_results: Type.Optional(
    Type.Number({
      description: "Maximum number of results to return (default: 3, max: 10)",
      minimum: 1,
      maximum: 10,
    }),
  ),
});

// ─── DuckDuckGo HTML search parser ──────────────────────────────────────────

/**
 * Parse search results from DuckDuckGo's HTML response.
 * DuckDuckGo does not provide a public free HTML scraping API,
 * so we parse the <a> tags from the results section.
 */
function parseDuckDuckGoResults(html: string): SearchResult[] {
  const results: SearchResult[] = [];

  // Extract title, URL, and snippet from DuckDuckGo HTML
  // Pattern: <a class="[ddg] result-link" href="url" title="title">
  // and <a href="url" title="title"> for secondary results
  const titlePattern = /<a class="[^"]*result-link[^"]*"[^>]*href="([^"]*?)"[^>]*title="([^"]*?)"[^>]*>/gi;
  let titleMatch;

  while ((titleMatch = titlePattern.exec(html)) !== null) {
    const url = titleMatch[1].replace(/&amp;/g, "&");
    const title = titleMatch[2].replace(/&amp;/g, "&");
    results.push({ title, url, snippet: "" });
  }

  // Fallback: extract any remaining href/title pairs from <a> tags
  if (results.length === 0) {
    const linkPattern = /<a[^>]*href="([^"]*?)"[^>]*title="([^"]*?)"[^>]*>/gi;
    let match;
    const seen = new Set<string>();

    while ((match = linkPattern.exec(html)) !== null) {
      const url = match[1].replace(/&amp;/g, "&").replace(/&amp;/g, "&");
      const title = match[2].replace(/&amp;/g, "&").replace(/&amp;/g, "&");

      // Skip anchor links, navigation, and footer content
      if (url.startsWith("#") || url.startsWith("javascript:") ||
          url.startsWith("mailto:") || title.toLowerCase().includes("privacy") ||
          seen.has(url)) continue;
      seen.add(url);

      results.push({ title, url, snippet: "" });
    }
  }

  return results;
}

// Alternative: use DuckDuckGo's instant answer / suggestion API (lighter weight)
async function searchDuckDuckGo(query: string, maxResults: number, signal?: AbortSignal): Promise<SearchResult[]> {
  // Use the DuckDuckGo HTML search URL
  const searchUrl = `https://html.duckduckgo.com/html/?q=${encodeURIComponent(query)}`;

  const response = await fetch(searchUrl, {
    headers: {
      "User-Agent": "pi-coding-agent/1.0 (+https://github.com/mariozechner/pi)",
      "Accept": "text/html,application/xhtml+xml",
    },
    signal,
  });

  if (!response.ok) {
    throw new Error(`DuckDuckGo search failed: ${response.status} ${response.statusText}`);
  }

  const html = await response.text();
  let results = parseDuckDuckGoResults(html);

  // Trim to maxResults
  return results.slice(0, maxResults);
}

// ─── Wikipedia search ───────────────────────────────────────────────────────

interface WikiResult {
  title: string;
  url: string;
  snippet: string;
  full_text?: string;
}

async function searchWikipedia(query: string, maxResults: number, signal?: AbortSignal): Promise<WikiResult[]> {
  // Wikipedia action API for search
  const apiUrl = `https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(query)}&srwhat=nusum&limit=${maxResults}&format=json&origin=*`;

  const response = await fetch(apiUrl, { signal });

  if (!response.ok) {
    throw new Error(`Wikipedia search failed: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();
  const wikiResults: WikiResult[] = [];

  for (const item of (data.query?.search || []) as any[]) {
    // Fetch snippet + full article text for each result
    const pageUrl = `https://en.wikipedia.org/w/api.php?action=query&prop=extracts&exintro=true&explaintext=true&titles=${encodeURIComponent(item.title)}&format=json&origin=*`;
    const pageRes = await fetch(pageUrl, { signal });
    const pageData = await pageRes.json();

    const pages = pageData.query?.pages;
    const pageId = Object.keys(pages || {})[0];
    const page = pageId ? pages[pageId] : null;

    wikiResults.push({
      title: item.title,
      url: `https://en.wikipedia.org/wiki/${encodeURIComponent(item.title)}`,
      snippet: item.snippet ? item.snippet.replace(/<\/?[a-z0-9]+[^>]*>/g, "") : "",
      full_text: page?.extract?.slice(0, 2000) || "",
    });
  }

  return wikiResults;
}

// ─── Types ──────────────────────────────────────────────────────────────────

interface SearchResult {
  title: string;
  title_url?: string;
  url: string;
  body: string;
}

// ─── Extension definition ───────────────────────────────────────────────────

export default function webSearchExtension(pi: ExtensionAPI) {

  // ── web_search tool ──────────────────────────────────────────────────────

  pi.registerTool({
    name: "web_search",
    label: "Web Search",
    description:
      "Search the web for information using DuckDuckGo. Use this tool to research any topic, find facts, or gather background knowledge. Returns title, URL, and snippet for each result. Specify max_results (1-12) to control how many results to return.",
    promptSnippet: "DuckDuckGo web search — search the internet for facts and background knowledge",
    promptGuidelines: [
      "Use this tool when you need to research a topic but don't have enough context.",
      "Prefer specific queries over broad ones for more relevant results.",
      "After getting search results, you may need to call fetch_url to read full pages for details.",
    ],
    parameters: webSearchParams,
    async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
      const { query, max_results = 5 } = params as Static<typeof webSearchParams>;

      onUpdate?.({
        content: [{ type: "text", text: `Searching: "${query}"` }],
        details: { progress: 25 },
      });

      try {
        const results = await searchDuckDuckGo(query, max_results, ctx.signal);

        const formatted = results.map((r, i) =>
          `[${i + 1}] ${r.title}\n${r.url}\n${r.snippet ? r.snippet.slice(0, 250) : "(no snippet)"}`
        ).join("\n\n");

        return {
          content: [
            { type: "text", text: `Found ${results.length} results for "${query}":\n\n${formatted}` },
          ],
          details: { results },
        };
      } catch (err: any) {
        return {
          content: [{ type: "text", text: `Search failed: ${err.message}` }],
          details: { error: err.message },
        };
      }
    },
  });

  // ── wikipedia_search tool ────────────────────────────────────────────────

  pi.registerTool({
    name: "wikipedia_search",
    label: "Wikipedia Search",
    description:
      "Search Wikipedia for detailed article content. Returns the article title, a summary snippet, and a full text extract (up to 2000 chars) for each result. Ideal for factual, well-sourced information on established topics.",
    promptSnippet: "Wikipedia search — look up detailed encyclopedic content on Wikipedia",
    promptGuidelines: [
      "Use this tool for well-defined topics that likely have Wikipedia articles (people, places, concepts, companies, technologies).",
      "Results include full text extracts, so you get more context than a typical search engine.",
    ],
    parameters: wikiSearchParams,
    async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
      const { query, max_results = 3 } = params as Static<typeof wikiSearchParams>;

      onUpdate?.({
        content: [{ type: "text", text: `Searching Wikipedia: "${query}"` }],
        details: { progress: 25 },
      });

      try {
        const results = await searchWikipedia(query, max_results, ctx.signal);

        const formatted = results.map((r, i) =>
          `[${i + 1}] ${r.title}\n${r.url}\nSummary: ${r.snippet.slice(0, 300)}\n\nFull extract (${(r.full_text || "").length} chars):\n${r.full_text?.slice(0, 1500) || ""}`
        ).join("\n\n---\n\n");

        return {
          content: [
            { type: "text", text: `Found ${results.length} Wikipedia results for "${query}":\n\n${formatted}` },
          ],
          details: { results },
        };
      } catch (err: any) {
        return {
          content: [{ type: "text", text: `Wikipedia search failed: ${err.message}` }],
          details: { error: err.message },
        };
      }
    },
  });
}

